mapper.select:
SELECT

FROM audit_logs al
LEFT JOIN user_accounts ua ON ua.id = al.operator_id


        al.action_type = #{actionType}


        AND al.operator_id = #{operatorId}


        AND al.created_at >= #{createdFrom}


        AND al.created_at <= #{createdTo}


ORDER BY al.created_at DESC, al.id DESC
LIMIT #{limit}
